-- ============ EMAIL TEMPLATES ============

INSERT INTO communication_templates (code, name, description, channel, category, subject, content_text, content_html, variables, is_system, tags) VALUES

('email_welcome_client', 'Bienvenida Cliente Email', 'Email de bienvenida profesional', 'email', 'bienvenida',
'Bienvenido/a a {{firm_name}} - Tu expediente {{matter_reference}}',
'Estimado/a {{client_name}}, Bienvenido/a a {{firm_name}}. Tu expediente {{matter_reference}} ha sido creado.',
'<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f8fafc;font-family:Segoe UI,Tahoma,Geneva,Verdana,sans-serif;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f8fafc;"><tr><td align="center" style="padding:40px 20px;"><table role="presentation" width="600" cellspacing="0" cellpadding="0" style="background-color:#ffffff;border-radius:16px;box-shadow:0 4px 6px rgba(0,0,0,0.05);"><tr><td style="background:linear-gradient(135deg,#3b82f6 0%,#1d4ed8 100%);padding:40px;border-radius:16px 16px 0 0;text-align:center;"><h1 style="margin:0;color:#ffffff;font-size:28px;font-weight:700;">¡Bienvenido/a!</h1><p style="margin:10px 0 0;color:rgba(255,255,255,0.9);font-size:16px;">{{firm_name}}</p></td></tr><tr><td style="padding:40px;"><p style="margin:0 0 20px;color:#1e293b;font-size:16px;line-height:1.6;">Estimado/a <strong>{{client_name}}</strong>,</p><p style="margin:0 0 20px;color:#475569;font-size:16px;line-height:1.6;">Es un placer darte la bienvenida. Tu expediente ha sido creado y ya estamos trabajando en tu caso.</p><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f1f5f9;border-radius:12px;margin:30px 0;"><tr><td style="padding:25px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td style="padding:8px 0;border-bottom:1px solid #e2e8f0;"><span style="color:#64748b;font-size:14px;">Referencia</span><br><span style="color:#1e293b;font-size:16px;font-weight:600;">{{matter_reference}}</span></td></tr><tr><td style="padding:8px 0;border-bottom:1px solid #e2e8f0;"><span style="color:#64748b;font-size:14px;">Tipo de expediente</span><br><span style="color:#1e293b;font-size:16px;font-weight:600;">{{matter_type}}</span></td></tr><tr><td style="padding:8px 0;"><span style="color:#64748b;font-size:14px;">Responsable</span><br><span style="color:#1e293b;font-size:16px;font-weight:600;">{{agent_name}}</span></td></tr></table></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding:20px 0;"><a href="{{portal_link}}" style="display:inline-block;background:linear-gradient(135deg,#3b82f6 0%,#1d4ed8 100%);color:#ffffff;text-decoration:none;padding:16px 40px;border-radius:8px;font-size:16px;font-weight:600;">Acceder a mi portal</a></td></tr></table><p style="margin:30px 0 0;color:#475569;font-size:16px;line-height:1.6;">Si tienes alguna pregunta, no dudes en contactarnos.</p><p style="margin:20px 0 0;color:#1e293b;font-size:16px;">Un cordial saludo,<br><strong>{{agent_name}}</strong><br><span style="color:#64748b;">{{firm_name}}</span></p></td></tr><tr><td style="background-color:#f8fafc;padding:30px;border-radius:0 0 16px 16px;text-align:center;border-top:1px solid #e2e8f0;"><p style="margin:0 0 10px;color:#64748b;font-size:14px;">{{firm_name}}</p><p style="margin:0;color:#94a3b8;font-size:12px;">{{firm_address}}</p></td></tr></table></td></tr></table></body></html>',
'[{"name": "client_name", "label": "Nombre del cliente", "required": true}, {"name": "firm_name", "label": "Nombre del despacho", "required": true}, {"name": "matter_reference", "label": "Referencia del expediente", "required": true}, {"name": "matter_type", "label": "Tipo de expediente", "required": true}, {"name": "agent_name", "label": "Nombre del agente", "required": true}, {"name": "portal_link", "label": "Enlace al portal", "required": false}, {"name": "firm_address", "label": "Dirección del despacho", "required": false}]',
true, ARRAY['bienvenida', 'onboarding', 'email']),

('email_invoice', 'Factura Email', 'Envío de factura profesional', 'email', 'facturacion',
'Factura {{invoice_number}} - {{firm_name}}',
'Adjuntamos la factura {{invoice_number}} por importe de {{amount}}. Vencimiento: {{due_date}}.',
'<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f8fafc;font-family:Segoe UI,Tahoma,Geneva,Verdana,sans-serif;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f8fafc;"><tr><td align="center" style="padding:40px 20px;"><table role="presentation" width="600" cellspacing="0" cellpadding="0" style="background-color:#ffffff;border-radius:16px;box-shadow:0 4px 6px rgba(0,0,0,0.05);"><tr><td style="background:linear-gradient(135deg,#14b8a6 0%,#0d9488 100%);padding:40px;border-radius:16px 16px 0 0;text-align:center;"><h1 style="margin:0;color:#ffffff;font-size:28px;font-weight:700;">📄 Factura</h1><p style="margin:10px 0 0;color:rgba(255,255,255,0.9);font-size:18px;">{{invoice_number}}</p></td></tr><tr><td style="padding:40px;"><p style="margin:0 0 20px;color:#1e293b;font-size:16px;line-height:1.6;">Estimado/a <strong>{{client_name}}</strong>,</p><p style="margin:0 0 30px;color:#475569;font-size:16px;line-height:1.6;">Adjuntamos la factura correspondiente a nuestros servicios profesionales.</p><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:linear-gradient(135deg,#f0fdfa 0%,#ccfbf1 100%);border-radius:12px;margin:20px 0;"><tr><td align="center" style="padding:30px;"><p style="margin:0;color:#0d9488;font-size:14px;text-transform:uppercase;letter-spacing:1px;">Importe total</p><p style="margin:10px 0 0;color:#0f766e;font-size:36px;font-weight:700;">{{amount}}</p></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="margin:30px 0;"><tr><td style="padding:15px 0;border-bottom:1px solid #e2e8f0;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td style="color:#64748b;font-size:14px;">Concepto</td><td align="right" style="color:#1e293b;font-size:14px;font-weight:600;">{{concept}}</td></tr></table></td></tr><tr><td style="padding:15px 0;border-bottom:1px solid #e2e8f0;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td style="color:#64748b;font-size:14px;">Fecha de emisión</td><td align="right" style="color:#1e293b;font-size:14px;font-weight:600;">{{issue_date}}</td></tr></table></td></tr><tr><td style="padding:15px 0;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td style="color:#64748b;font-size:14px;">Fecha de vencimiento</td><td align="right" style="color:#ef4444;font-size:14px;font-weight:600;">{{due_date}}</td></tr></table></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding:20px 0;"><a href="{{payment_link}}" style="display:inline-block;background:linear-gradient(135deg,#14b8a6 0%,#0d9488 100%);color:#ffffff;text-decoration:none;padding:16px 40px;border-radius:8px;font-size:16px;font-weight:600;margin-right:10px;">💳 Pagar ahora</a></td></tr></table></td></tr><tr><td style="background-color:#f8fafc;padding:30px;border-radius:0 0 16px 16px;text-align:center;border-top:1px solid #e2e8f0;"><p style="margin:0;color:#64748b;font-size:14px;">{{firm_name}}</p></td></tr></table></td></tr></table></body></html>',
'[{"name": "client_name", "label": "Nombre del cliente", "required": true}, {"name": "invoice_number", "label": "Número de factura", "required": true}, {"name": "amount", "label": "Importe", "required": true}, {"name": "concept", "label": "Concepto", "required": true}, {"name": "issue_date", "label": "Fecha de emisión", "required": true}, {"name": "due_date", "label": "Fecha de vencimiento", "required": true}, {"name": "payment_link", "label": "Enlace de pago", "required": false}, {"name": "firm_name", "label": "Nombre del despacho", "required": true}]',
true, ARRAY['facturacion', 'factura', 'email']),

('email_deadline_reminder', 'Recordatorio de Plazo Email', 'Aviso profesional de plazo próximo', 'email', 'plazos',
'⚠️ Plazo próximo: {{matter_reference}} - Acción requerida',
'Recordatorio: El plazo para {{action_required}} vence el {{deadline_date}}.',
'<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f8fafc;font-family:Segoe UI,Tahoma,Geneva,Verdana,sans-serif;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f8fafc;"><tr><td align="center" style="padding:40px 20px;"><table role="presentation" width="600" cellspacing="0" cellpadding="0" style="background-color:#ffffff;border-radius:16px;box-shadow:0 4px 6px rgba(0,0,0,0.05);"><tr><td style="background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);padding:40px;border-radius:16px 16px 0 0;text-align:center;"><h1 style="margin:0;color:#ffffff;font-size:28px;font-weight:700;">⏰ Recordatorio de Plazo</h1><p style="margin:10px 0 0;color:rgba(255,255,255,0.9);font-size:16px;">Acción requerida</p></td></tr><tr><td style="padding:40px;"><p style="margin:0 0 20px;color:#1e293b;font-size:16px;line-height:1.6;">Estimado/a <strong>{{client_name}}</strong>,</p><p style="margin:0 0 30px;color:#475569;font-size:16px;line-height:1.6;">Le recordamos que tiene un plazo importante próximo a vencer que requiere su atención.</p><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:linear-gradient(135deg,#fef3c7 0%,#fde68a 100%);border-radius:12px;border-left:4px solid #f59e0b;margin:20px 0;"><tr><td style="padding:25px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td><p style="margin:0 0 10px;color:#92400e;font-size:14px;font-weight:600;text-transform:uppercase;">Fecha límite</p><p style="margin:0;color:#78350f;font-size:24px;font-weight:700;">{{deadline_date}}</p></td><td align="right"><span style="display:inline-block;background-color:#f59e0b;color:#ffffff;padding:8px 16px;border-radius:20px;font-size:14px;font-weight:600;">{{days_remaining}} días</span></td></tr></table></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f8fafc;border-radius:12px;margin:30px 0;"><tr><td style="padding:25px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td style="padding:10px 0;border-bottom:1px solid #e2e8f0;"><span style="color:#64748b;font-size:14px;">Expediente</span><br><span style="color:#1e293b;font-size:16px;font-weight:600;">{{matter_reference}}</span></td></tr><tr><td style="padding:10px 0;"><span style="color:#64748b;font-size:14px;">Acción requerida</span><br><span style="color:#1e293b;font-size:16px;font-weight:600;">{{action_required}}</span></td></tr></table></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding:20px 0;"><a href="{{portal_link}}" style="display:inline-block;background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);color:#ffffff;text-decoration:none;padding:16px 40px;border-radius:8px;font-size:16px;font-weight:600;">Ver expediente</a></td></tr></table><p style="margin:20px 0 0;color:#1e293b;font-size:16px;">Atentamente,<br><strong>{{agent_name}}</strong><br><span style="color:#64748b;">{{firm_name}}</span></p></td></tr><tr><td style="background-color:#f8fafc;padding:30px;border-radius:0 0 16px 16px;text-align:center;border-top:1px solid #e2e8f0;"><p style="margin:0;color:#64748b;font-size:14px;">{{firm_name}}</p></td></tr></table></td></tr></table></body></html>',
'[{"name": "client_name", "label": "Nombre del cliente", "required": true}, {"name": "matter_reference", "label": "Referencia del expediente", "required": true}, {"name": "deadline_date", "label": "Fecha límite", "required": true}, {"name": "days_remaining", "label": "Días restantes", "required": true}, {"name": "action_required", "label": "Acción requerida", "required": true}, {"name": "portal_link", "label": "Enlace al portal", "required": false}, {"name": "agent_name", "label": "Nombre del agente", "required": true}, {"name": "firm_name", "label": "Nombre del despacho", "required": true}]',
true, ARRAY['plazos', 'recordatorio', 'email']),

('email_trademark_granted', 'Marca Concedida Email', 'Notificación de concesión de marca', 'email', 'legal',
'🎉 ¡Enhorabuena! Tu marca {{trademark_name}} ha sido concedida',
'Nos complace comunicarle que su marca {{trademark_name}} ha sido concedida con número de registro {{registration_number}}.',
'<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f8fafc;font-family:Segoe UI,Tahoma,Geneva,Verdana,sans-serif;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f8fafc;"><tr><td align="center" style="padding:40px 20px;"><table role="presentation" width="600" cellspacing="0" cellpadding="0" style="background-color:#ffffff;border-radius:16px;box-shadow:0 4px 6px rgba(0,0,0,0.05);"><tr><td style="background:linear-gradient(135deg,#22c55e 0%,#16a34a 100%);padding:50px 40px;border-radius:16px 16px 0 0;text-align:center;"><div style="font-size:60px;margin-bottom:20px;">🎉</div><h1 style="margin:0;color:#ffffff;font-size:32px;font-weight:700;">¡Enhorabuena!</h1><p style="margin:15px 0 0;color:rgba(255,255,255,0.95);font-size:18px;">Tu marca ha sido concedida</p></td></tr><tr><td style="padding:40px;"><p style="margin:0 0 20px;color:#1e293b;font-size:16px;line-height:1.6;">Estimado/a <strong>{{client_name}}</strong>,</p><p style="margin:0 0 30px;color:#475569;font-size:16px;line-height:1.6;">Nos complace comunicarle que su solicitud de registro de marca ha sido aprobada. Su marca está ahora protegida legalmente.</p><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:linear-gradient(135deg,#f0fdf4 0%,#dcfce7 100%);border-radius:16px;border:2px solid #22c55e;margin:30px 0;"><tr><td align="center" style="padding:35px;"><p style="margin:0;color:#15803d;font-size:14px;text-transform:uppercase;letter-spacing:2px;font-weight:600;">Marca registrada</p><p style="margin:15px 0;color:#166534;font-size:32px;font-weight:700;">{{trademark_name}}</p><div style="display:inline-block;background-color:#22c55e;color:#ffffff;padding:8px 20px;border-radius:20px;font-size:14px;font-weight:600;">✓ Registrada oficialmente</div></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="margin:30px 0;"><tr><td width="50%" style="padding:15px;background-color:#f8fafc;border-radius:12px 0 0 12px;"><p style="margin:0;color:#64748b;font-size:12px;text-transform:uppercase;">Nº de registro</p><p style="margin:5px 0 0;color:#1e293b;font-size:18px;font-weight:700;">{{registration_number}}</p></td><td width="50%" style="padding:15px;background-color:#f8fafc;border-radius:0 12px 12px 0;"><p style="margin:0;color:#64748b;font-size:12px;text-transform:uppercase;">Territorio</p><p style="margin:5px 0 0;color:#1e293b;font-size:18px;font-weight:700;">{{territory}}</p></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding:30px 0;"><a href="{{certificate_link}}" style="display:inline-block;background:linear-gradient(135deg,#22c55e 0%,#16a34a 100%);color:#ffffff;text-decoration:none;padding:16px 40px;border-radius:8px;font-size:16px;font-weight:600;">📄 Descargar certificado</a></td></tr></table><p style="margin:20px 0 0;color:#1e293b;font-size:16px;">¡Felicidades por este logro!<br><br><strong>{{agent_name}}</strong><br><span style="color:#64748b;">{{firm_name}}</span></p></td></tr><tr><td style="background-color:#f8fafc;padding:30px;border-radius:0 0 16px 16px;text-align:center;border-top:1px solid #e2e8f0;"><p style="margin:0;color:#64748b;font-size:14px;">{{firm_name}}</p></td></tr></table></td></tr></table></body></html>',
'[{"name": "client_name", "label": "Nombre del cliente", "required": true}, {"name": "trademark_name", "label": "Nombre de la marca", "required": true}, {"name": "registration_number", "label": "Número de registro", "required": true}, {"name": "territory", "label": "Territorio", "required": true}, {"name": "expiry_date", "label": "Fecha de vencimiento", "required": true}, {"name": "certificate_link", "label": "Enlace al certificado", "required": false}, {"name": "agent_name", "label": "Nombre del agente", "required": true}, {"name": "firm_name", "label": "Nombre del despacho", "required": true}]',
true, ARRAY['legal', 'marca', 'concesion', 'email']),

('email_meeting_confirmation', 'Confirmación de Reunión Email', 'Confirmación profesional de cita', 'email', 'confirmaciones',
'📅 Confirmación de reunión - {{meeting_date}}',
'Confirmamos su reunión para el {{meeting_date}} a las {{meeting_time}}.',
'<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f8fafc;font-family:Segoe UI,Tahoma,Geneva,Verdana,sans-serif;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f8fafc;"><tr><td align="center" style="padding:40px 20px;"><table role="presentation" width="600" cellspacing="0" cellpadding="0" style="background-color:#ffffff;border-radius:16px;box-shadow:0 4px 6px rgba(0,0,0,0.05);"><tr><td style="background:linear-gradient(135deg,#8b5cf6 0%,#7c3aed 100%);padding:40px;border-radius:16px 16px 0 0;text-align:center;"><h1 style="margin:0;color:#ffffff;font-size:28px;font-weight:700;">📅 Reunión Confirmada</h1></td></tr><tr><td style="padding:40px;"><p style="margin:0 0 20px;color:#1e293b;font-size:16px;line-height:1.6;">Estimado/a <strong>{{client_name}}</strong>,</p><p style="margin:0 0 30px;color:#475569;font-size:16px;line-height:1.6;">Le confirmamos su reunión con los siguientes detalles:</p><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f5f3ff;border-radius:12px;margin:20px 0;"><tr><td style="padding:25px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td style="padding:10px 0;border-bottom:1px solid #e9d5ff;"><span style="color:#7c3aed;font-size:14px;font-weight:600;">📆 Fecha</span><br><span style="color:#1e293b;font-size:18px;font-weight:700;">{{meeting_date}}</span></td></tr><tr><td style="padding:10px 0;border-bottom:1px solid #e9d5ff;"><span style="color:#7c3aed;font-size:14px;font-weight:600;">⏰ Hora</span><br><span style="color:#1e293b;font-size:18px;font-weight:700;">{{meeting_time}}</span></td></tr><tr><td style="padding:10px 0;border-bottom:1px solid #e9d5ff;"><span style="color:#7c3aed;font-size:14px;font-weight:600;">📍 Lugar</span><br><span style="color:#1e293b;font-size:16px;">{{meeting_location}}</span></td></tr><tr><td style="padding:10px 0;"><span style="color:#7c3aed;font-size:14px;font-weight:600;">👤 Con</span><br><span style="color:#1e293b;font-size:16px;">{{agent_name}}</span></td></tr></table></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding:20px 0;"><a href="{{meeting_link}}" style="display:inline-block;background:linear-gradient(135deg,#8b5cf6 0%,#7c3aed 100%);color:#ffffff;text-decoration:none;padding:16px 40px;border-radius:8px;font-size:16px;font-weight:600;">🔗 Unirse a videollamada</a></td></tr></table><p style="margin:30px 0 0;color:#475569;font-size:14px;">¿Necesita modificar la cita? Contacte con nosotros con al menos 24h de antelación.</p><p style="margin:20px 0 0;color:#1e293b;font-size:16px;">Un saludo,<br><strong>{{firm_name}}</strong></p></td></tr><tr><td style="background-color:#f8fafc;padding:30px;border-radius:0 0 16px 16px;text-align:center;border-top:1px solid #e2e8f0;"><p style="margin:0;color:#64748b;font-size:14px;">{{firm_name}}</p></td></tr></table></td></tr></table></body></html>',
'[{"name": "client_name", "label": "Nombre del cliente", "required": true}, {"name": "meeting_date", "label": "Fecha de la reunión", "required": true}, {"name": "meeting_time", "label": "Hora", "required": true}, {"name": "meeting_location", "label": "Lugar", "required": true}, {"name": "agent_name", "label": "Nombre del agente", "required": true}, {"name": "meeting_link", "label": "Enlace de videollamada", "required": false}, {"name": "firm_name", "label": "Nombre del despacho", "required": true}]',
true, ARRAY['reunion', 'confirmacion', 'email']),

('email_renewal_notice', 'Aviso de Renovación Email', 'Notificación de renovación próxima', 'email', 'recordatorios',
'🔄 Renovación próxima: {{ip_name}} - Acción requerida',
'Su {{ip_type}} {{ip_name}} requiere renovación antes del {{expiry_date}}.',
