form:uppercase;">Vence</p><p style="margin:5px 0 0;color:#7f1d1d;font-size:18px;font-weight:700;">{{expiry_date}}</p></td><td width="50%" style="padding:15px;background-color:#f0fdf4;border-radius:0 12px 12px 0;text-align:center;"><p style="margin:0;color:#16a34a;font-size:12px;text-transform:uppercase;">Coste renovación</p><p style="margin:5px 0 0;color:#14532d;font-size:18px;font-weight:700;">{{renewal_cost}}</p></td></tr></table><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td align="center" style="padding:20px 0;"><a href="{{portal_link}}" style="display:inline-block;background:linear-gradient(135deg,#ec4899 0%,#db2777 100%);color:#ffffff;text-decoration:none;padding:16px 40px;border-radius:8px;font-size:16px;font-weight:600;">Confirmar renovación</a></td></tr></table><p style="margin:20px 0 0;color:#1e293b;font-size:16px;">Atentamente,<br><strong>{{agent_name}}</strong><br><span style="color:#64748b;">{{firm_name}}</span></p></td></tr><tr><td style="background-color:#f8fafc;padding:30px;border-radius:0 0 16px 16px;text-align:center;border-top:1px solid #e2e8f0;"><p style="margin:0;color:#64748b;font-size:14px;">{{firm_name}}</p></td></tr></table></td></tr></table></body></html>',
